{
    "level": "A1–B1",
    "intro": "W tym dziale zebrano tematy, które pomagają poprawnie używać w języku angielskim <strong>rzeczowników</strong>, <strong>rodzajników</strong> i <strong>wyrażeń ilościowych</strong>.",
    "rules": [
        {
            "label": "NOUNS",
            "color": "emerald",
            "text": "<strong>Formy rzeczownika</strong> — singular/plural, formy regularne i nieregularne.",
            "example": "Plural Nouns, Irregular Plurals"
        },
        {
            "label": "ARTICLES",
            "color": "blue",
            "text": "<strong>Rodzajniki</strong> — a/an/the oraz zero article.",
            "example": "Articles A / An / The"
        },
        {
            "label": "QUANTITY",
            "color": "amber",
            "text": "<strong>Ilość</strong> — some, any, much, many, few, little, a lot of.",
            "example": "Some / Any, Much / Many, Few / Little"
        }
    ]
}

{
    "title": "Co wchodzi w skład tej kategorii",
    "intro": "Najważniejsze podtematy logicznie połączone w tej kategorii to:",
    "items": [
        {
            "label": "PLURAL",
            "title": "Liczba mnoga rzeczowników",
            "subtitle": "Zasady -s, -es, -ies, -ves, irregular plurals oraz nouns występujące tylko w singular albo tylko w plural."
        },
        {
            "label": "ARTICLES",
            "title": "Rodzajniki",
            "subtitle": "Użycie a/an/the, zero article, typowe błędy i najważniejsze wyjątki."
        },
        {
            "label": "QUANTITY",
            "title": "Ilość",
            "subtitle": "Countable vs uncountable nouns, some/any, much/many, few/little i pokrewne konstrukcje."
        }
    ]
}

{
    "title": "Kiedy otwierać ten dział",
    "sections": [
        {
            "label": "Forma wyrazu",
            "color": "emerald",
            "description": "Gdy trzeba zdecydować, której formy rzeczownika użyć: <strong>singular</strong> czy <strong>plural</strong>.",
            "examples": [
                {
                    "en": "one child / two children",
                    "ua": "jedno dziecko / dwoje dzieci"
                },
                {
                    "en": "a box / three boxes",
                    "ua": "jedno pudełko / trzy pudełka"
                }
            ]
        },
        {
            "label": "Rodzajnik",
            "color": "blue",
            "description": "Gdy trzeba zrozumieć, czy użyć <strong>a/an/the</strong>, czy zostawić rzeczownik bez rodzajnika.",
            "examples": [
                {
                    "en": "a book",
                    "ua": "dowolna książka"
                },
                {
                    "en": "the book",
                    "ua": "konkretna książka"
                }
            ]
        },
        {
            "label": "Ilość",
            "color": "amber",
            "description": "Gdy trzeba wybrać wyraz ilościowy, taki jak <strong>some, any, much, many, few, little</strong>.",
            "examples": [
                {
                    "en": "many books",
                    "ua": "dużo książek"
                },
                {
                    "en": "little water",
                    "ua": "mało wody"
                }
            ]
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Plural Nouns",
            "current": false
        },
        {
            "label": "Articles A / An / The",
            "current": false
        },
        {
            "label": "Countable vs Uncountable Nouns",
            "current": false
        },
        {
            "label": "Some / Any",
            "current": false
        },
        {
            "label": "Much / Many",
            "current": false
        },
        {
            "label": "Few / Little",
            "current": false
        }
    ]
}
